  resolver?: ChannelResolverAdapter;
  actions?: ChannelMessageActionAdapter;
  heartbeat?: ChannelHeartbeatAdapter;
  agentTools?: ChannelAgentToolFactory | ChannelAgentTool[];
};
```

**Config Schema Definition:**
```typescript
export type ChannelConfigSchema = {
  schema: Record<string, unknown>;
  uiHints?: Record<string, ChannelConfigUiHint>;
  runtime?: ChannelConfigRuntimeSchema;
};
```

### 2. **Core SDK Helpers** 
*File: `/src/plugin-sdk/core.ts`*

**`defineChannelPluginEntry`** - Main helper for registering channel plugins:
- Wraps `definePluginEntry()` and registers the channel capability
- Optionally exposes extra full-runtime registration (tools, gateway handlers)
- Signature: `defineChannelPluginEntry<TPlugin>(options: DefineChannelPluginEntryOptions<TPlugin>): DefinedChannelPluginEntry<TPlugin>`
- Returns object with `id`, `name`, `description`, `configSchema`, `register()`, and `channelPlugin`

**`defineSetupPluginEntry`** - Minimal setup-entry helper for channels with separate `setup-entry.ts`:
```typescript
export function defineSetupPluginEntry<TPlugin>(plugin: TPlugin) {
  return { plugin };
}
```

**`createChatChannelPlugin`** - Higher-level builder for chat-style channels that compose:
- Scoped DM security
- Text pairing
- Reply threading
- Attached send results
- Signature: `createChatChannelPlugin<TResolvedAccount, Probe, Audit>(params: { base, security?, pairing?, threading?, outbound? }): ChannelPlugin`

**`getChatChannelMeta`** - Gets metadata for chat-style channels

**Helper Functions:**
- `buildChannelOutboundSessionRoute()` - Builds canonical outbound session route payload
- `stripChannelTargetPrefix()` - Remove known provider prefixes
- `stripTargetKindPrefix()` - Remove generic target-kind prefixes (user:, group:, etc.)

**`createChannelPluginBase`** - Shared base object builder for channels that override few optional surfaces
- Returns: `CreatedChannelPluginBase<TResolvedAccount>`

### 3. **Plugin Runtime Store** 
*File: `/src/plugin-sdk/runtime-store.ts`*

```typescript
export function createPluginRuntimeStore<T>(errorMessage: string): {
  setRuntime: (next: T) => void;
  clearRuntime: () => void;
  tryGetRuntime: () => T | null;
  getRuntime: () => T;
}
```

A simple mutable runtime slot for accessing the `PluginRuntime` once initialized, with strict error handling if accessed before initialization.

### 4. **Plugin SDK Entrypoints Registry** 
*File: `/scripts/lib/plugin-sdk-entrypoints.json`*

Lists 245 exported SDK subpaths including:
- Core: `index`, `core`, `provider-setup`, `sandbox`, `routing`, `runtime`, `setup`
- Channel-specific: `channel-setup`, `channel-reply-pipeline`, `channel-runtime`, `outbound-runtime`
- Provider-specific: `provider-setup`, `provider-entry`, `provider-catalog-shared`
- Bundled plugins: `discord`, `slack`, `telegram`, `matrix`, `mattermost`, `signal`, `line`, `whatsapp`, `feishu`, `zalo`, `irc`, `msteams`, `googlechat`, etc.

### 5. **Package.json Exports** 
*File: `/package.json`*

Exports structure (sample):
```json
{
  "exports": {
    ".": "./dist/index.js",
    "./plugin-sdk": { "types": "./dist/plugin-sdk/index.d.ts", "default": "./dist/plugin-sdk/index.js" },
    "./plugin-sdk/core": { "types": "./dist/plugin-sdk/core.d.ts", "default": "./dist/plugin-sdk/core.js" },
    "./plugin-sdk/runtime": { "types": "./dist/plugin-sdk/runtime.d.ts", "default": "./dist/plugin-sdk/runtime.js" },
    "./plugin-sdk/channel-setup": { "types": "./dist/plugin-sdk/channel-setup.d.ts", "default": "./dist/plugin-sdk/channel-setup.js" },
    // ... 240+ more exports covering all SDK subpaths
  }
}
```

### 6. **Telegram Plugin Reference Implementation**

**Package Metadata** - `/extensions/telegram/package.json`:
```json
{
  "name": "@openclaw/telegram",
  "version": "2026.4.1-beta.1",
  "dependencies": {
    "@grammyjs/runner": "^2.0.3",
    "@grammyjs/transformer-throttler": "^1.2.1",
    "grammy": "^1.41.1"
  },
  "openclaw": {
    "extensions": ["./index.ts"],
    "setupEntry": "./setup-entry.ts",
    "channel": {
      "id": "telegram",
      "label": "Telegram",
      "selectionLabel": "Telegram (Bot API)",
      "docsPath": "/channels/telegram",
      "markdownCapable": true
    },
    "bundle": {
      "stageRuntimeDependencies": true
    }
  }
}
```

**Plugin Manifest** - `/extensions/telegram/openclaw.plugin.json`:
```json
{
  "id": "telegram",
  "channels": ["telegram"],
  "configSchema": {
    "type": "object",
    "additionalProperties": false,
    "properties": {}
  }
}
```

**Entry Point** - `/extensions/telegram/index.ts`:
```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { telegramPlugin } from "./src/channel.js";
import { setTelegramRuntime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "telegram",
  name: "Telegram",
  description: "Telegram channel plugin",
  plugin: telegramPlugin as ChannelPlugin,
  setRuntime: setTelegramRuntime,
});
```

### Key Design Patterns:

1. **Separation of Concerns**: Channel logic lives in `src/channels/plugins/` but plugins import through `openclaw/plugin-sdk/*`
2. **Setup vs. Full Runtime**: `defineChannelPluginEntry` supports dual-mode registration (setup-only or full)
3. **Async Config Resolution**: `configSchema` can be a function for lazy evaluation
4. **Scoped Runtime Access**: `createPluginRuntimeStore` provides safe lazy-initialization of runtime context
5. **Chat Channel Convenience**: `createChatChannelPlugin` provides higher-level builder for common patterns (DM security, pairing, threading)
6. **Message Session Routes**: Extensible routing via `ChannelOutboundSessionRoute` for multi-account/multi-target scenarios

All these files work together to provide a clean, extensible contract for both bundled plugins (like Telegram) and third-party plugin developers.

