1	import {
2	  DEFAULT_ACCOUNT_ID,
3	  normalizeAccountId,
4	  normalizeOptionalAccountId,
5	} from "openclaw/plugin-sdk/account-id";
6	import {
7	  listCombinedAccountIds,
8	  resolveListedDefaultAccountId,
9	} from "openclaw/plugin-sdk/account-resolution";
10	import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
11	import type { OpenClawConfig } from "../api.js";
12	import type { NostrProfile } from "./config-schema.js";
13	import { DEFAULT_RELAYS } from "./default-relays.js";
14	import { getPublicKeyFromPrivate } from "./nostr-bus.js";
15	
16	export interface NostrAccountConfig {
17	  enabled?: boolean;
18	  name?: string;
19	  defaultAccount?: string;
20	  privateKey?: SecretInput;
21	  relays?: string[];
22	  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
23	  allowFrom?: Array<string | number>;
24	  profile?: NostrProfile;
25	}
26	
27	export interface ResolvedNostrAccount {
28	  accountId: string;
29	  name?: string;
30	  enabled: boolean;
31	  configured: boolean;
32	  privateKey: string;
33	  publicKey: string;
34	  relays: string[];
35	  profile?: NostrProfile;
36	  config: NostrAccountConfig;
37	}
38	
39	function resolveConfiguredDefaultNostrAccountId(cfg: OpenClawConfig): string | undefined {
40	  const nostrCfg = (cfg.channels as Record<string, unknown> | undefined)?.nostr as
41	    | NostrAccountConfig
42	    | undefined;
43	  return normalizeOptionalAccountId(nostrCfg?.defaultAccount);
44	}
45	
46	/**
47	 * List all configured Nostr account IDs
48	 */
49	export function listNostrAccountIds(cfg: OpenClawConfig): string[] {
50	  const nostrCfg = (cfg.channels as Record<string, unknown> | undefined)?.nostr as
51	    | NostrAccountConfig
52	    | undefined;
53	  const privateKey = normalizeSecretInputString(nostrCfg?.privateKey);
54	  return listCombinedAccountIds({
55	    configuredAccountIds: [],
56	    implicitAccountId: privateKey
57	      ? (resolveConfiguredDefaultNostrAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
58	      : undefined,
59	  });
60	}
61	
62	/**
63	 * Get the default account ID
64	 */
65	export function resolveDefaultNostrAccountId(cfg: OpenClawConfig): string {
66	  return resolveListedDefaultAccountId({
67	    accountIds: listNostrAccountIds(cfg),
68	    configuredDefaultAccountId: resolveConfiguredDefaultNostrAccountId(cfg),
69	  });
70	}
71	
72	/**
73	 * Resolve a Nostr account from config
74	 */
75	export function resolveNostrAccount(opts: {
76	  cfg: OpenClawConfig;
77	  accountId?: string | null;
78	}): ResolvedNostrAccount {
79	  const accountId = normalizeAccountId(opts.accountId ?? resolveDefaultNostrAccountId(opts.cfg));
80	  const nostrCfg = (opts.cfg.channels as Record<string, unknown> | undefined)?.nostr as
81	    | NostrAccountConfig
82	    | undefined;
83	
84	  const baseEnabled = nostrCfg?.enabled !== false;
85	  const privateKey = normalizeSecretInputString(nostrCfg?.privateKey) ?? "";
86	  const configured = Boolean(privateKey);
87	
88	  let publicKey = "";
89	  if (privateKey) {
90	    try {
91	      publicKey = getPublicKeyFromPrivate(privateKey);
92	    } catch {
93	      // Invalid key - leave publicKey empty, configured will indicate issues
94	    }
95	  }
96	
97	  return {
98	    accountId,
99	    name: nostrCfg?.name?.trim() || undefined,
100	    enabled: baseEnabled,
101	    configured,
102	    privateKey,
103	    publicKey,
104	    relays: nostrCfg?.relays ?? DEFAULT_RELAYS,
105	    profile: nostrCfg?.profile,
106	    config: {
107	      enabled: nostrCfg?.enabled,
108	      name: nostrCfg?.name,
109	      privateKey: nostrCfg?.privateKey,
110	      relays: nostrCfg?.relays,
111	      dmPolicy: nostrCfg?.dmPolicy,
112	      allowFrom: nostrCfg?.allowFrom,
113	      profile: nostrCfg?.profile,
114	    },
115	  };
116	}
