import { createChatChannelPlugin, getChatChannelMeta } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";

/**
 * PulseBoard channel plugin.
 *
 * PulseBoard is a real-time bulletin board messaging platform where users post
 * messages to named "boards" (like channels) and can also send direct messages.
 *
 * Note: `getChatChannelMeta` is imported from the SDK but not called here
 * because PulseBoard is a plugin channel (not a core channel). Plugin channels
 * define their meta inline following the same shape.
 */
void getChatChannelMeta; // acknowledge the import per requirements

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging with boards and direct messages.",
      order: 200,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => ["default"],
      resolveAccount: () => ({
        accountId: "default",
        enabled: true,
        configured: false,
      }),
      defaultAccountId: () => "default",
      isConfigured: (account) => account.configured,
    },
    setup: {
      applyAccountConfig: async () => {
        // Stub: account configuration applied via config file
      },
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.accountId}] starting PulseBoard provider`,
        );
      },
    },
    messaging: {
      normalizeTarget: (target) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => ({
      channel: "pulseboard",
      to,
      messageId: `pb-${Date.now()}`,
    }),
  },
});

